# Identify a kmer in a text string and then identify the indices where it matches

# text = """"""
# kmer = "GAACGCTGA"



# Take input values from user
# text = input("Please enter your text: ")
# OR READ IN TEXT <---- skipping try and except
file_name = input("Please enter file name: ")
with open(file_name, 'r') as file:
    text = file.read()

# print(text)
# text = input("Please enter your text: ")
kmer = input("Please enter your kmer: ")

# Matching indices
count_list = []
def match_index(text, kmer):
    for i in range(len(text) - len(kmer)+1):
        if text[i:i+len(kmer)] == kmer:
            count_list.append(i)
    return count_list

result = match_index(text, kmer)
print("kmer positions broken by space :-) :", *result)
